use aiken/interval
use cardano/transaction.{InlineDatum, OutputReference, Transaction}

pub type EscrowDatum {
  deadline: Int,
}

validator timed_escrow {
  spend(
    datum: Option<EscrowDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        interval.is_entirely_after(d.deadline, self.validity_range)
    }
  }
}

use cardano/governance.{GovernanceActionId}
use cardano/transaction.{Transaction, Voter}
use aiken/crypto.{VerificationKeyHash}

pub type VoteRedeemer {
  required_key: VerificationKeyHash,
}

validator governance_vote_validator {
  vote(redeemer: Data, voter: Voter, _proposal: GovernanceActionId, _self: Transaction) {
    expect typed: VoteRedeemer = redeemer
    when voter is {
      ConstitutionalCommitteeMember { credential, .. } ->
        when credential is {
          VerificationKeyCredential(key_hash) -> key_hash == typed.required_key
          _ -> False
        }
      _ -> False
    }
  }
}

use aiken/collection/list
use cardano/governance.{GovernanceActionId}
use cardano/transaction.{Transaction, Voter}

pub type DelegateConfig {
  delegate_key: ByteArray,
}

validator delegate_vote {
  vote(
    redeemer: Data,
    voter: Voter,
    proposal: GovernanceActionId,
    self: Transaction,
  ) {
    let delegate_config: DelegateConfig = redeemer
    expect typed: DelegateConfig = delegate_config
    list.has(self.extra_signatories, typed.delegate_key)
  }

  else(_) {
    fail
  }
}
